fragment:


		{{sts-google-api-url}}
		POST

			application/x-www-form-urlencoded

		@{
            var azureToken = (string)context.Variables["azure-ad-token"];
            var audience = "//iam.googleapis.com/projects/{{gcp-project-number}}/locations/global/workloadIdentityPools/{{gcp-workload-identity-id}}/providers/{{gcp-workload-identity-provider-name}}";
            return $"grant_type=urn:ietf:params:oauth:grant-type:token-exchange"
                + $"&subject_token_type=urn:ietf:params:oauth:token-type:jwt"
                + $"&requested_token_type=urn:ietf:params:oauth:token-type:access_token"
                + $"&audience={System.Net.WebUtility.UrlEncode(audience)}"
                + $"&scope={System.Net.WebUtility.UrlEncode("https://www.googleapis.com/auth/cloud-platform")}"
                + $"&subject_token={System.Net.WebUtility.UrlEncode(azureToken)}";
        }

	<set-variable name="gcp-federated-token" value="@{
        var body = ((IResponse)context.Variables["gcp-sts-response"]).Body.As();
        return (string)body["access_token"];
    }" />

		@("Bearer " + (string)context.Variables["gcp-federated-token"])
